from rtSque import zmqports
from rtSque.loggers import levels
from rtSque.loggers.publisher import *
from threading import Thread, Lock


class LogSubscriber(Thread):
    def __init__(self, port, level, url=None):
        super(LogSubscriber, self).__init__()
        ctx = zmq.Context.instance()
        self.subscriber = ctx.socket(zmq.SUB)
        if url is None:
            url = 'tcp://localhost:' + str(port)
        self.subscriber.connect(url)
        self.url = url
        self.subscriber.setsockopt(zmq.SUBSCRIBE, zmqports.PUB_CHANNEL)
        self.receiving = True
        self.level = level

    def run(self):
        print('ready to subscribe to ' + str(self.url))
        while self.receiving:
            try:
                msg = self.subscriber.recv_multipart(zmq.NOBLOCK)
                self.handle_msg(msg)
            except zmq.ZMQError:
                pass
            time.sleep(0.02)
        self.subscriber.setsockopt(zmq.LINGER, 0)
        self.subscriber.close()


def safe_convert_ts(timestamp, original_format, export_format):
    import _strptime
    from datetime import datetime
    t = datetime.strptime(timestamp, original_format)
    return datetime.strftime(t, export_format)